-- Seed script for LockIn Workouts
-- Generated from src/lib/exercises.ts and src/lib/workoutStore.ts
begin;

create extension if not exists "pgcrypto";

create or replace function slug_uuid(input text)
returns uuid
language sql
immutable
as $$
  select (
    substr(md5(input),1,8) || '-' ||
    substr(md5(input),9,4) || '-' ||
    substr(md5(input),13,4) || '-' ||
    substr(md5(input),17,4) || '-' ||
    substr(md5(input),21,12)
  )::uuid;
$$;

truncate table workout_tags, exercise_tags, workout_intervals, workouts, exercises, tags restart identity cascade;







commit;
