insert into exercises (id, name, description, type, posture, infographic_key)
values
  (slug_uuid('exercise:jumping-jacks'), 'Jumping Jacks', 'Stand tall, jump feet wide as arms raise overhead, then jump back to start with soft knees.', 'standing'::exercise_type, 'standing'::posture_type, 'jumping-jacks'),
  (slug_uuid('exercise:high-knees'), 'High Knees', 'Run in place and drive knees toward hip height while keeping chest up and core braced.', 'standing'::exercise_type, 'standing'::posture_type, 'high-knees'),
  (slug_uuid('exercise:air-squats'), 'Air Squats', 'Sit hips back and down with heels planted, then stand by pressing through mid-foot.', 'standing'::exercise_type, 'standing'::posture_type, 'air-squats'),
  (slug_uuid('exercise:reverse-lunges'), 'Alternating Reverse Lunges', 'Step one leg back, lower both knees to about 90 degrees, then push through front heel to return.', 'standing'::exercise_type, 'standing'::posture_type, 'reverse-lunges'),
  (slug_uuid('exercise:standing-calf-raises'), 'Standing Calf Raises', 'Rise onto the balls of your feet with control, pause briefly at top, then lower slowly.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-calf-raises'),
  (slug_uuid('exercise:standing-knee-drives'), 'Standing Knee Drives', 'Drive one knee up toward chest while balancing on the other leg, then alternate sides.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-knee-drives'),
  (slug_uuid('exercise:standing-oblique-crunches'), 'Standing Oblique Crunches', 'Bring elbow and same-side knee toward each other to crunch through your side, then switch.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-oblique-crunches'),
  (slug_uuid('exercise:bodyweight-good-mornings'), 'Bodyweight Good Mornings', 'Hinge at hips with a flat back and slight knee bend, then squeeze glutes to return upright.', 'standing'::exercise_type, 'standing'::posture_type, 'bodyweight-good-mornings'),
  (slug_uuid('exercise:side-steps'), 'Side Steps', 'Step laterally right and left with soft knees and an athletic stance, keeping tension in your hips.', 'standing'::exercise_type, 'standing'::posture_type, 'side-steps'),
  (slug_uuid('exercise:butt-kicks'), 'Butt Kicks', 'Jog in place and bring heels toward glutes while keeping your chest tall and core engaged.', 'standing'::exercise_type, 'standing'::posture_type, 'butt-kicks'),
  (slug_uuid('exercise:standing-front-kicks'), 'Standing Front Kicks', 'Kick one leg forward to hip height with control, lower it, then alternate sides.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-front-kicks'),
  (slug_uuid('exercise:curtsy-lunges'), 'Curtsy Lunges', 'Step one leg diagonally behind the other, lower with control, then return and switch sides.', 'standing'::exercise_type, 'standing'::posture_type, 'curtsy-lunges'),
  (slug_uuid('exercise:standing-hip-abductions'), 'Standing Hip Abductions', 'Lift one leg out to the side without leaning, pause, and lower slowly before switching legs.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-hip-abductions'),
  (slug_uuid('exercise:standing-toe-touches'), 'Standing Toe Touches', 'Alternate reaching opposite hand to opposite foot while hinging at hips and keeping movements controlled.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-toe-touches'),
  (slug_uuid('exercise:skater-steps'), 'Skater Steps', 'Step or hop side to side, letting the trailing leg move behind you while maintaining balance.', 'standing'::exercise_type, 'standing'::posture_type, 'skater-steps'),
  (slug_uuid('exercise:standing-arm-circles'), 'Standing Arm Circles', 'Extend arms out at shoulder height and draw controlled circles, forward then backward.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-arm-circles'),
  (slug_uuid('exercise:march-and-reach'), 'March and Reach', 'March in place while reaching one arm overhead at a time, keeping your torso tall.', 'standing'::exercise_type, 'standing'::posture_type, 'march-and-reach'),
  (slug_uuid('exercise:standing-cross-punches'), 'Standing Cross Punches', 'Throw alternating cross-body punches with core rotation and stable lower body stance.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-cross-punches'),
  (slug_uuid('exercise:standing-hamstring-curls'), 'Standing Hamstring Curls', 'Curl one heel toward your glutes, lower with control, and alternate legs.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-hamstring-curls'),
  (slug_uuid('exercise:lateral-lunges'), 'Lateral Lunges', 'Step wide to one side, sit hips back on that leg, then push back to center and switch.', 'standing'::exercise_type, 'standing'::posture_type, 'lateral-lunges'),
  (slug_uuid('exercise:standing-windmills'), 'Standing Windmills', 'Hinge and rotate to reach one hand toward opposite foot while the other arm points up.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-windmills'),
  (slug_uuid('exercise:speed-skips'), 'Speed Skips', 'Perform quick low-impact skipping steps in place with rhythmic arm drive.', 'standing'::exercise_type, 'standing'::posture_type, 'speed-skips'),
  (slug_uuid('exercise:standing-quad-pulls'), 'Standing Quad Pulls', 'Pull one ankle toward glute to open the front of the thigh, then alternate dynamically.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-quad-pulls'),
  (slug_uuid('exercise:standing-side-bends'), 'Standing Side Bends', 'Reach one arm overhead and bend sideways to lengthen and contract the side body.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-side-bends'),
  (slug_uuid('exercise:neck-rolls'), 'Neck Rolls', 'Gently roll your head in controlled circles to release neck tension before training.', 'standing'::exercise_type, 'standing'::posture_type, 'neck-rolls'),
  (slug_uuid('exercise:shoulder-rolls'), 'Shoulder Rolls', 'Roll shoulders up, back, and down to warm the upper back and shoulder joints.', 'standing'::exercise_type, 'standing'::posture_type, 'shoulder-rolls'),
  (slug_uuid('exercise:standing-torso-rotations'), 'Standing Torso Rotations', 'Rotate your trunk side to side to prepare your spine and core for movement.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-torso-rotations'),
  (slug_uuid('exercise:hip-circles'), 'Hip Circles', 'Draw smooth circles with your hips to loosen the hips and lower back.', 'standing'::exercise_type, 'standing'::posture_type, 'hip-circles'),
  (slug_uuid('exercise:ankle-circles'), 'Ankle Circles', 'Lift one foot and rotate the ankle joint to improve ankle mobility and balance.', 'standing'::exercise_type, 'standing'::posture_type, 'ankle-circles'),
  (slug_uuid('exercise:standing-quad-stretch'), 'Standing Quad Stretch', 'Pull heel to glute to lengthen the front thigh and open the hip flexors.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-quad-stretch'),
  (slug_uuid('exercise:dynamic-hamstring-scoops'), 'Dynamic Hamstring Scoops', 'Sweep hands toward toes with a straight leg to warm hamstrings dynamically.', 'standing'::exercise_type, 'standing'::posture_type, 'dynamic-hamstring-scoops'),
  (slug_uuid('exercise:standing-calf-stretch'), 'Standing Calf Stretch', 'Step one foot back and press heel down to stretch calf and Achilles.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-calf-stretch'),
  (slug_uuid('exercise:overhead-side-reach-stretch'), 'Overhead Side Reach Stretch', 'Reach overhead and arc side to side to lengthen lats and obliques.', 'standing'::exercise_type, 'standing'::posture_type, 'overhead-side-reach-stretch'),
  (slug_uuid('exercise:chest-opener-stretch'), 'Chest Opener Stretch', 'Open through the chest and shoulders by pulling arms behind your body.', 'standing'::exercise_type, 'standing'::posture_type, 'chest-opener-stretch'),
  (slug_uuid('exercise:cat-cow-standing'), 'Standing Cat-Cow', 'Alternate rounding and arching the spine in standing to mobilize the back before training.', 'standing'::exercise_type, 'standing'::posture_type, 'cat-cow-standing'),
  (slug_uuid('exercise:standing-figure-four-stretch'), 'Standing Figure-Four Stretch', 'Cross ankle over opposite thigh and sit back slightly to open glutes and hips.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-figure-four-stretch'),
  (slug_uuid('exercise:standing-lat-stretch'), 'Standing Lat Stretch', 'Reach overhead and lean slightly to target the lats and side body.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-lat-stretch'),
  (slug_uuid('exercise:wrist-circles'), 'Wrist Circles', 'Rotate wrists through full range to prepare hands and forearms for pressing and plank work.', 'standing'::exercise_type, 'standing'::posture_type, 'wrist-circles'),
  (slug_uuid('exercise:standing-adductor-rocks'), 'Standing Adductor Rocks', 'Shift side to side into a lateral stance to open inner thighs and hips dynamically.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-adductor-rocks'),
  (slug_uuid('exercise:standing-forward-fold-stretch'), 'Standing Forward Fold Stretch', 'Hinge at the hips and relax into a gentle hamstring and lower-back stretch.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-forward-fold-stretch'),
  (slug_uuid('exercise:cross-body-shoulder-stretch'), 'Cross-Body Shoulder Stretch', 'Pull one arm across your chest to release rear shoulder tension.', 'standing'::exercise_type, 'standing'::posture_type, 'cross-body-shoulder-stretch'),
  (slug_uuid('exercise:overhead-triceps-stretch'), 'Overhead Triceps Stretch', 'Reach one elbow overhead and gently press for triceps and lat flexibility.', 'standing'::exercise_type, 'standing'::posture_type, 'overhead-triceps-stretch'),
  (slug_uuid('exercise:standing-calf-hold-stretch'), 'Standing Calf Hold Stretch', 'Step one leg back and press the heel down to lengthen calf muscles.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-calf-hold-stretch'),
  (slug_uuid('exercise:standing-quad-hold-stretch'), 'Standing Quad Hold Stretch', 'Pull one ankle toward your glute to stretch the front thigh.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-quad-hold-stretch'),
  (slug_uuid('exercise:standing-figure-four-hold'), 'Standing Figure-Four Hold', 'Cross one ankle over opposite thigh and sit back to stretch glutes.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-figure-four-hold'),
  (slug_uuid('exercise:standing-hamstring-hold-stretch'), 'Standing Hamstring Hold Stretch', 'Extend one heel forward and hinge gently to stretch the hamstring.', 'standing'::exercise_type, 'standing'::posture_type, 'standing-hamstring-hold-stretch'),
  (slug_uuid('exercise:side-neck-stretch'), 'Side Neck Stretch', 'Tilt your head to one side with gentle hand pressure to release neck tightness.', 'standing'::exercise_type, 'standing'::posture_type, 'side-neck-stretch'),
  (slug_uuid('exercise:chest-clasp-stretch'), 'Chest Clasp Stretch', 'Clasp hands behind your back and open your chest to ease shoulder tension.', 'standing'::exercise_type, 'standing'::posture_type, 'chest-clasp-stretch'),
  (slug_uuid('exercise:deep-breathing-arm-sweeps'), 'Deep Breathing Arm Sweeps', 'Slow arm sweeps coordinated with breathing to lower heart rate post-workout.', 'standing'::exercise_type, 'standing'::posture_type, 'deep-breathing-arm-sweeps'),
  (slug_uuid('exercise:inchworm-walkouts'), 'Inchworm Walkouts', 'Hinge down, walk your hands forward to a plank, then walk back and stand.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'inchworm-walkouts'),
  (slug_uuid('exercise:plank-shoulder-taps'), 'Plank Shoulder Taps', 'From a plank, tap opposite shoulders while resisting hip sway.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'plank-shoulder-taps'),
  (slug_uuid('exercise:mountain-climbers'), 'Mountain Climbers', 'Drive knees toward chest from plank position at a steady or fast pace.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'mountain-climbers'),
  (slug_uuid('exercise:bodyweight-split-squats'), 'Bodyweight Split Squats', 'Use a staggered stance and lower straight down, then rise and repeat each side.', 'standing'::exercise_type, 'standing'::posture_type, 'bodyweight-split-squats'),
  (slug_uuid('exercise:glute-bridges'), 'Glute Bridges', 'Lift hips from the floor by squeezing glutes, then lower with control.', 'bodyweight'::exercise_type, 'back'::posture_type, 'glute-bridges'),
  (slug_uuid('exercise:dead-bugs'), 'Dead Bugs', 'Alternate opposite arm and leg extensions while keeping your low back stable.', 'bodyweight'::exercise_type, 'back'::posture_type, 'dead-bugs'),
  (slug_uuid('exercise:bird-dogs'), 'Bird Dogs', 'From all-fours, extend opposite arm and leg while staying balanced.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'bird-dogs'),
  (slug_uuid('exercise:hollow-body-hold'), 'Hollow Body Hold', 'Hold a curved core position with lower back pressed into the floor.', 'bodyweight'::exercise_type, 'back'::posture_type, 'hollow-body-hold'),
  (slug_uuid('exercise:wall-sits'), 'Wall Sits', 'Sit against a wall with knees bent and hold the position.', 'standing'::exercise_type, 'standing'::posture_type, 'wall-sits'),
  (slug_uuid('exercise:reverse-snow-angels'), 'Reverse Snow Angels', 'Lying face down, sweep arms from overhead to hips to train upper back.', 'bodyweight'::exercise_type, 'prone'::posture_type, 'reverse-snow-angels'),
  (slug_uuid('exercise:superman-holds'), 'Superman Holds', 'Lift chest, arms, and legs off the floor to engage posterior chain.', 'bodyweight'::exercise_type, 'prone'::posture_type, 'superman-holds'),
  (slug_uuid('exercise:pike-shoulder-taps'), 'Pike Shoulder Taps', 'From a pike position, alternate shoulder taps while maintaining stability.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'pike-shoulder-taps'),
  (slug_uuid('exercise:lateral-bounds'), 'Lateral Bounds', 'Explosively bound side to side, landing softly and under control.', 'standing'::exercise_type, 'standing'::posture_type, 'lateral-bounds'),
  (slug_uuid('exercise:tuck-jumps'), 'Tuck Jumps', 'Jump vertically and bring knees upward before landing softly.', 'standing'::exercise_type, 'standing'::posture_type, 'tuck-jumps'),
  (slug_uuid('exercise:jump-squats'), 'Jump Squats', 'Perform a squat and explode upward into a jump.', 'standing'::exercise_type, 'standing'::posture_type, 'jump-squats'),
  (slug_uuid('exercise:bear-crawls'), 'Bear Crawls', 'Crawl forward and back with knees hovering just off the floor.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'bear-crawls'),
  (slug_uuid('exercise:crab-toe-touches'), 'Crab Toe Touches', 'From crab position, reach one hand to opposite foot and alternate.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'crab-toe-touches'),
  (slug_uuid('exercise:plank-jacks'), 'Plank Jacks', 'In plank, jump feet out and in while maintaining a strong core.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'plank-jacks'),
  (slug_uuid('exercise:walking-lunges'), 'Walking Lunges', 'Step forward into lunges continuously with upright posture.', 'standing'::exercise_type, 'standing'::posture_type, 'walking-lunges'),
  (slug_uuid('exercise:single-leg-romanian-deadlifts'), 'Single-Leg Romanian Deadlifts', 'Hinge on one leg while extending the other back, then return to stand.', 'standing'::exercise_type, 'standing'::posture_type, 'single-leg-romanian-deadlifts'),
  (slug_uuid('exercise:push-ups'), 'Push-Ups', 'Lower chest toward the floor from plank, then press back up with a rigid body line.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'push-ups'),
  (slug_uuid('exercise:forearm-plank-hold'), 'Forearm Plank Hold', 'Hold a straight-body plank on forearms while breathing and bracing your core.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'forearm-plank-hold'),
  (slug_uuid('exercise:side-plank-dips'), 'Side Plank Dips', 'In a side plank, lower hips slightly then lift using obliques.', 'bodyweight'::exercise_type, 'hands'::posture_type, 'side-plank-dips'),
  (slug_uuid('exercise:bicycle-crunches'), 'Bicycle Crunches', 'Alternate elbow-to-opposite-knee while extending the other leg.', 'bodyweight'::exercise_type, 'back'::posture_type, 'bicycle-crunches'),
  (slug_uuid('exercise:lying-leg-raises'), 'Lying Leg Raises', 'Raise straight legs from the floor and lower with core control.', 'bodyweight'::exercise_type, 'back'::posture_type, 'lying-leg-raises'),
  (slug_uuid('exercise:prone-swimmers'), 'Prone Swimmers', 'Lying face down, move arms in a swimming pattern while lifting chest slightly.', 'bodyweight'::exercise_type, 'prone'::posture_type, 'prone-swimmers');
