insert into workouts (id, name, description, estimated_minutes, is_warmup, is_cooldown)
values
  (slug_uuid('workout:0'), '5-Minute Warm-Up Flow', 'A quick full-body mobility warm-up using only stretching and movement-prep exercises, one minute each.', 5, true, false),
  (slug_uuid('workout:0b'), '5-Minute Cooldown Flow', 'A gentle post-workout cooldown with five mobility and stretching drills, one minute each.', 5, false, true),
  (slug_uuid('workout:1'), 'Standing Conditioning', 'A fast-paced standing cardio session to elevate heart rate and improve stamina with low equipment needs.', 30, false, false),
  (slug_uuid('workout:2'), 'Lower Body Standing', 'Targets quads, glutes, hamstrings, and calves through standing leg patterns and single-leg control.', 28, false, false),
  (slug_uuid('workout:3'), 'Standing Cardio Mix', 'An interval-focused standing workout that blends agility and rhythm for full-body cardio conditioning.', 30, false, false),
  (slug_uuid('workout:4'), 'Bodyweight Push and Plank', 'Builds upper-body and core endurance with plank mechanics, push strength, and anti-rotation control.', 30, false, false),
  (slug_uuid('workout:5'), 'Bodyweight Core Control', 'Focused core session emphasizing trunk control, anti-extension strength, and rotational endurance.', 30, false, false),
  (slug_uuid('workout:6'), 'Bodyweight Posterior and Crawl', 'Strengthens posterior chain and shoulder endurance through prone work and crawling locomotion.', 30, false, false);
